import { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import axiosInstance from '../axiosConfig';

const TourForm = ({ tours, setTours, editingTour, setEditingTour, onSuccess, onClose }) => {
  const { user } = useAuth();

  const [formData, setFormData] = useState({ 
    title: '', 
    location: '',
    startDate: '',
    endDate: '',
    description: '',
    importantNotes: '',
    capacity: '',
    price: '', 
    discount: '',
    status: 'Available'
  });

  // 圖片上傳相關狀態
  const [imageFile, setImageFile] = useState(null);
  const [imagePreview, setImagePreview] = useState(null);

  useEffect(() => {
    if (editingTour) {
      setFormData({ ...editingTour });
      if (editingTour.imageUrl) setImagePreview(editingTour.imageUrl);
    } else {
      setFormData({ 
        title: '', location: '', startDate: '', endDate: '', 
        description: '', importantNotes: '', capacity: '', 
        price: '', discount: '', status: 'Available' 
      });
      setImageFile(null);
      setImagePreview(null);
    }
  }, [editingTour]);

  // 處理圖片選擇與預覽
  const handleImageChange = (e) => {
    const file = e.target.files[0];
    if (file) {
      setImageFile(file);
      const reader = new FileReader();
      reader.onloadend = () => {
        setImagePreview(reader.result);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      // 使用 FormData 來處理包含檔案的表單
      const data = new FormData();
      Object.keys(formData).forEach(key => data.append(key, formData[key]));
      if (imageFile) data.append('image', imageFile);

      const config = {
        headers: { 
          Authorization: `Bearer ${user.token}`,
          'Content-Type': 'multipart/form-data' // 告訴後端這是檔案上傳
        },
      };

      if (editingTour) {
        // 編輯 (Update)
        const response = await axiosInstance.put(`/api/tours/${editingTour._id}`, data, config);
        setTours(tours.map((t) => (t._id === response.data._id ? response.data : t)));
      } else {
        // 新增 (Create)
        const response = await axiosInstance.post('/api/tours', data, config);
        setTours([...tours, response.data]);
      }

      alert('Success!');
      if (onSuccess) onSuccess(); // 關閉表單並刷新列表
    } catch (error) {
      console.error(error);
      alert('Error saving tour. Check backend logs.');
    }
  };

  return (
    <div className="max-w-[420px] mx-auto bg-white min-h-screen pb-10 shadow-inner">
      {/* Header */}
      <div className="flex items-center p-4 border-b sticky top-0 bg-white z-10">
        <button type="button" onClick={onClose} className="text-xl px-2">←</button>
        <h1 className="flex-1 text-center font-bold text-lg">
          {editingTour ? 'Edit Tour' : 'Add Tour Package'}
        </h1>
        <button type="button" onClick={onClose} className="text-xl px-2">🏠</button>
      </div>

      <form onSubmit={handleSubmit} className="p-4 space-y-5 text-sm">
        {/* Tour Title */}
        <div>
          <label className="block font-bold mb-1 text-gray-700">Tour Title</label>
          <input
            type="text"
            placeholder="Enter tour title"
            value={formData.title}
            onChange={(e) => setFormData({ ...formData, title: e.target.value })}
            className="w-full p-3 border border-gray-200 rounded-xl bg-gray-50 focus:bg-white focus:ring-2 focus:ring-emerald-400 outline-none transition-all"
            required
          />
        </div>

        {/* Location */}
        <div>
          <label className="block font-bold mb-1 text-gray-700">Location</label>
          <input
            type="text"
            placeholder="Enter tour location"
            value={formData.location}
            onChange={(e) => setFormData({ ...formData, location: e.target.value })}
            className="w-full p-3 border border-gray-200 rounded-xl bg-gray-50 focus:bg-white"
          />
        </div>

        {/* Dates */}
        <div className="flex space-x-3">
          <div className="flex-1">
            <label className="block font-bold mb-1 text-gray-700 text-xs">Start Date</label>
            <input
              type="date"
              value={formData.startDate ? formData.startDate.split('T')[0] : ''}
              onChange={(e) => setFormData({ ...formData, startDate: e.target.value })}
              className="w-full p-3 border border-gray-200 rounded-xl bg-gray-50 text-gray-500"
            />
          </div>
          <div className="flex-1">
            <label className="block font-bold mb-1 text-gray-700 text-xs">End Date</label>
            <input
              type="date"
              value={formData.endDate ? formData.endDate.split('T')[0] : ''}
              onChange={(e) => setFormData({ ...formData, endDate: e.target.value })}
              className="w-full p-3 border border-gray-200 rounded-xl bg-gray-50 text-gray-500"
            />
          </div>
        </div>

        {/* Description */}
        <div>
          <label className="block font-bold mb-1 text-gray-700">What is it about</label>
          <textarea
            placeholder="Enter description"
            rows="3"
            value={formData.description}
            onChange={(e) => setFormData({ ...formData, description: e.target.value })}
            className="w-full p-3 border border-gray-200 rounded-xl bg-gray-50"
          />
        </div>

        {/* Real Image Upload */}
        <div>
          <label className="block font-bold mb-1 text-gray-700">Upload cover picture</label>
          <label className="cursor-pointer block">
            <div className={`border-2 border-dashed rounded-2xl p-4 text-center transition-all ${imagePreview ? 'border-emerald-400' : 'border-gray-200 text-gray-400'}`}>
              {imagePreview ? (
                <img src={imagePreview} alt="Preview" className="w-full h-32 object-cover rounded-xl" />
              ) : (
                <div className="py-4">
                  <span className="block text-2xl mb-1">☁️</span>
                  <p className="font-bold text-gray-600">Click to upload</p>
                  <p className="text-[10px]">PNG, JPG or GIF (max. 5MB)</p>
                </div>
              )}
              <input type="file" accept="image/*" onChange={handleImageChange} className="hidden" />
            </div>
          </label>
        </div>

        {/* Price & Capacity */}
        <div className="flex space-x-3">
          <div className="flex-1">
            <label className="block font-bold mb-1 text-gray-700">Price (AUD)</label>
            <input
              type="number"
              value={formData.price}
              onChange={(e) => setFormData({ ...formData, price: e.target.value })}
              className="w-full p-3 border border-gray-200 rounded-xl bg-gray-50"
              required
            />
          </div>
          <div className="flex-1">
            <label className="block font-bold mb-1 text-gray-700">Capacity</label>
            <input
              type="number"
              value={formData.capacity}
              onChange={(e) => setFormData({ ...formData, capacity: e.target.value })}
              className="w-full p-3 border border-gray-200 rounded-xl bg-gray-50"
            />
          </div>
        </div>

        {/* Submit */}
        <button 
          type="submit" 
          className="w-full bg-emerald-500 text-white font-bold py-4 rounded-2xl hover:bg-emerald-600 shadow-lg shadow-emerald-200 transition-all active:scale-95"
        >
          {editingTour ? 'Update Tour' : 'Submit'}
        </button>
      </form>
    </div>
  );
};

export default TourForm;
